INSERT OR REPLACE INTO niche_calendars (niche_tag, config_md, updated_at) VALUES ('devotional-hindu', '# Niche Calendar — Devotional / Hindu

For clients with `niche_tag: devotional-hindu`. (Shinel Studios mentioned devotional creators are part of the roster.)

## Weekly rhythms
- **Monday** — Shiva (specifically Sawan Mondays July–Aug, demand spikes 5x)
- **Tuesday** — Hanuman, Mangaldosh remedies
- **Thursday** — Sai Baba, Vishnu, Brihaspati, gurus generally
- **Saturday** — Shani, Hanuman (again, Hanuman Chalisa search peaks)

## Monthly rhythms
- **Pradosh** — twice a month, Shiva content
- **Ekadashi** — twice a month, Vishnu / fasting content
- **Amavasya / Purnima** — major spiritual anchors
- **Sankashti Chaturthi** — Ganesha, monthly

## Festival anchors (next 12 months — refresh annually)
- **Mahashivratri** — Feb/Mar (biggest Shiva spike of the year)
- **Holi** — March
- **Ram Navami** — March/April
- **Hanuman Jayanti** — April
- **Akshaya Tritiya** — April/May
- **Sawan begins** — late July (Shiva content runs hot for ~30 days)
- **Janmashtami** — Aug/Sep
- **Ganesh Chaturthi** — Aug/Sep (10-day Ganesha content window)
- **Navratri / Dussehra** — Sep/Oct (9 days of Devi-themed content)
- **Karwa Chauth** — Oct/Nov
- **Diwali / Dhanteras / Bhai Dooj** — Oct/Nov (largest non-religious-specific demand spike)
- **Chhath Puja** — Oct/Nov
- **Tulsi Vivah** — Nov
- **Geeta Jayanti** — Dec
- **Makar Sankranti / Pongal** — January

## Research task instructions
For devotional clients, the research task should:
1. Identify which day-deity tie-in is happening tomorrow (Mon=Shiva, etc.)
2. Check upcoming festivals in next 14 days
3. Propose ideas that tie the day''s deity + nearest festival to the client''s pillars (chalisa playlists, story-of-deity videos, vrat-katha shorts, mantra meditations)
', CURRENT_TIMESTAMP);
INSERT OR REPLACE INTO niche_calendars (niche_tag, config_md, updated_at) VALUES ('gaming-bgmi', '# Niche Calendar — Gaming / BGMI India

